import { expect, type Page } from "@playwright/test";
import { MockClient } from "request-mocking-protocol";
import { test as base } from "./test-fixture";

export const test = base.extend<{ mockServerRequest: MockClient }>({
  mockServerRequest: async ({ context }, use) => {
    const mockClient = new MockClient();
    mockClient.onChange = async (headers) =>
      context.setExtraHTTPHeaders(headers);
    await use(mockClient);
  },
});

const descriptionText = "Help us build momentum with a quick sign-up.";
const actionPageUrlPattern =
  /https?:\/\/[^/]+\/public\/v3\/action_pages\/[^/?]+/;
const leadSubmissionUrlPattern =
  /https?:\/\/[^/]+\/public\/v3\/submissions\/lead\/?(?:\?.*)?$/;
const leadPagePath = "/lead/demo-org/lead-token";

const mockActionPage = {
  id: "ap_123",
  headerTitleText: "Join the Movement",
  description: descriptionText,
  account: {
    id: "acct_123",
    displayName: "Demo Org",
    allowCustomCss: false,
    slug: "demo-org",
  },
};

async function mockPublicActionPage(mockServerRequest: MockClient) {
  await mockServerRequest.GET(actionPageUrlPattern, { body: mockActionPage });
}

async function mockLeadSubmission(
  mockServerRequest: MockClient,
  body: Record<string, unknown> = {},
) {
  await mockServerRequest.PUT(leadSubmissionUrlPattern, {
    body: {
      id: "lead_123",
      actionPage: {
        id: "ap_123",
        name: "Join the Movement",
        pageType: "lead",
      },
      addressAttributes: {
        city: "Austin",
        country: "US",
        line1: "123 Main St",
        postalCode: "78701",
        region: "TX",
      },
      callbackUrl: null,
      ...body,
    },
  });
}

async function gotoLeadPage(page: Page) {
  await Promise.all([
    page.waitForResponse((response) => {
      if (!response.ok()) {
        return false;
      }

      const requestUrl = response.url();
      const isActionPageRequest = actionPageUrlPattern.test(requestUrl);
      const isLeadDocumentRequest =
        response.request().resourceType() === "document" &&
        requestUrl.includes(leadPagePath);

      return isActionPageRequest || isLeadDocumentRequest;
    }),
    page.goto(leadPagePath),
  ]);
}

test("shows the heading", async ({ page, mockServerRequest }) => {
  await mockPublicActionPage(mockServerRequest);

  await gotoLeadPage(page);

  await expect(
    page.getByRole("heading", { name: "Join the Movement" }),
  ).toBeVisible();
});

test("shows the description when provided", async ({
  page,
  mockServerRequest,
}) => {
  await mockPublicActionPage(mockServerRequest);

  await gotoLeadPage(page);

  await expect(page.getByText(descriptionText)).toBeVisible();
});

test("shows all form fields", async ({ page, mockServerRequest }) => {
  await mockPublicActionPage(mockServerRequest);

  await gotoLeadPage(page);

  // Text inputs
  await expect(page.getByLabel("Email", { exact: true })).toBeVisible();
  await expect(page.getByLabel("Phone")).toBeVisible();
  await expect(page.getByLabel("First name")).toBeVisible();
  await expect(page.getByLabel("Last name")).toBeVisible();
  // must use name over label here because the component modfies the label
  await expect(page.getByRole("combobox", { name: "Address" })).toBeVisible();
  await expect(
    page.getByRole("textbox", { name: "Address line" }),
  ).toBeVisible();
  await expect(page.getByLabel("City")).toBeVisible();
  await expect(page.getByLabel("State")).toBeVisible();
  await expect(page.getByLabel("Postal code")).toBeVisible();

  // Checkbox
  await expect(page.getByLabel("Send me updates by email")).toBeVisible();

  // Submit button
  await expect(page.getByRole("button", { name: "Submit" })).toBeVisible();

  // Login link
  await expect(page.getByText("Already have an account?")).toBeVisible();
});

test("clears required validation after filling required fields", async ({
  page,
  mockServerRequest,
}) => {
  await mockPublicActionPage(mockServerRequest);
  await gotoLeadPage(page);

  await page.getByLabel("Email", { exact: true }).fill("test@example.com");
  await page.getByLabel("Phone").fill("5555555555");
  await page.getByLabel("First name").fill("Ada");
  await page.getByLabel("Last name").fill("Lovelace");
  await page.getByRole("combobox", { name: "Address" }).fill("123 Main St");
  await page.getByLabel("City").fill("Austin");
  await page.getByLabel("State").fill("TX");
  await page.getByLabel("Postal code").fill("78701");

  await expect(page.getByText("Required")).toHaveCount(0);
});

test("does not render the description when missing", async ({
  page,
  mockServerRequest,
}) => {
  await mockServerRequest.GET(actionPageUrlPattern, {
    body: {
      ...mockActionPage,
      description: undefined,
    },
  });

  await gotoLeadPage(page);

  await expect(page.getByText(descriptionText)).toHaveCount(0);
});

test("redirects when callbackUrl is a valid URL", async ({
  page,
  mockServerRequest,
}) => {
  await mockPublicActionPage(mockServerRequest);

  const validCallbackUrl = "/thanks";
  await mockLeadSubmission(mockServerRequest, {
    callbackUrl: validCallbackUrl,
  });

  await gotoLeadPage(page);

  await page.getByLabel("Email", { exact: true }).fill("test@example.com");
  await page.getByLabel("Phone").fill("5555555555");
  await page.getByLabel("First name").fill("Ada");
  await page.getByLabel("Last name").fill("Lovelace");
  await page.getByRole("combobox", { name: "Address" }).fill("123 Main St");
  await page.getByLabel("City").fill("Austin");
  await page.getByLabel("State").fill("TX");
  await page.getByLabel("Postal code").fill("78701");

  // Valid callbackUrl should redirect.
  await expect(page.getByRole("button", { name: "Submit" })).toBeEnabled();
  await page.getByRole("button", { name: "Submit" }).click();
  await expect(page).toHaveURL(new RegExp(`${validCallbackUrl}$`));
});

test("does not redirect when callbackUrl is invalid", async ({
  page,
  mockServerRequest,
}) => {
  await mockPublicActionPage(mockServerRequest);

  await mockLeadSubmission(mockServerRequest, {
    callbackUrl: "//this-is-not-a-valid-url",
  });

  await gotoLeadPage(page);

  await page.getByLabel("Email", { exact: true }).fill("test@example.com");
  await page.getByLabel("Phone").fill("5555555555");
  await page.getByLabel("First name").fill("Ada");
  await page.getByLabel("Last name").fill("Lovelace");
  await page.getByRole("combobox", { name: "Address" }).fill("123 Main St");
  await page.getByLabel("City").fill("Austin");
  await page.getByLabel("State").fill("TX");
  await page.getByLabel("Postal code").fill("78701");

  // Invalid callbackUrl should not redirect.
  await page.getByRole("button", { name: "Submit" }).click();
  await expect(page).toHaveURL(/\/lead\/demo-org\/lead-token$/);
});

test("submits email and phone opt-in values in payload", async ({
  page,
