import { useQuery } from "@tanstack/react-query";
import type { ApiClientError } from "#types/client.ts";
import { getApiClient } from "../../../apiClientInstance";
import { makeSearchParams } from "../../../utils/makeSearchParams";
import type { SmartyAddress } from "./types";

type UseGetSmartyAutocompleteProps = {
  accountSlug?: string;
  filter: {
    searchTerm: string;
  };
  /**
   * The `selected` parameter is used for addresses with multiple entries,
   * e.g. apartment buildings.
   * https://www.smarty.com/docs/cloud/us-autocomplete-pro-api#pro-secondary-expansion
   */
  selected?: string;
  enabled?: boolean;
};

export const useGetSmartyAutocomplete = ({
  accountSlug,
  filter,
  selected,
  enabled = true,
}: UseGetSmartyAutocompleteProps) => {
  const params = makeSearchParams({
    accountSlug,
    q: filter?.searchTerm,
    selected,
  });

  const query = useQuery<SmartyAddress[], ApiClientError>({
    enabled: !!filter?.searchTerm && enabled,
    initialData: [],
    queryFn: () => {
      if (!filter?.searchTerm || !accountSlug) {
        return [];
      }

      return getApiClient(false, "public").get<SmartyAddress[]>(
        `/smarty/autocomplete?${params.toString()}`,
      );
    },
    queryKey: ["smarty-autocomplete", filter?.searchTerm],
  });

  return {
    error: query.error,
    isError: query.isError,
    isLoading: query.isLoading,
    suggestions: query.data,
  };
};

